#!/usr/bin/env python3
# =============================================================================
# SCRIPT METADATA (Generated by g_code)
# =============================================================================
"""
Step ID: step05
Step Name: compute_effect_sizes
RQ: results/ch7/7.7.3
Generated: 2026-01-09

PURPOSE:
Compute effect sizes (Cohen's f², semi-partial r²), AIC weights, and incremental
validity test (Model 5 vs Model 1) with bootstrap CIs.

EXPECTED INPUTS:
  - results/ch7/7.7.3/data/step04_model_results.csv
    Model-level statistics including R² values
  - results/ch7/7.7.3/data/step03_analysis_dataset.csv
    Raw data for bootstrap resampling

EXPECTED OUTPUTS:
  - results/ch7/7.7.3/data/step05_effect_sizes.csv
    Columns: ['model', 'f2', 'f2_CI_lower', 'f2_CI_upper', 'sr2', 'sr2_CI_lower', 'sr2_CI_upper', 'AIC_weight']
  - results/ch7/7.7.3/data/step05_incremental_validity.csv
    Columns: ['delta_R2', 'F_stat', 'df1', 'df2', 'p_uncorrected', 'p_bonferroni', 'delta_R2_CI']

VALIDATION CRITERIA:
  - Cohen's f² bounded [0, 5.0]
  - AIC weights sum to 1.0
  - Incremental validity test (Model 5 vs Model 1)

g_code REASONING:
- Approach: Compute effect sizes from R², bootstrap for CIs, AIC weights, F-test for incremental validity
- Why this approach: Standard effect size reporting + model comparison
- Data flow: Load R² -> compute f² -> bootstrap CIs -> AIC weights -> incremental test -> save
- Expected performance: ~20 seconds (bootstrap iterations)

IMPLEMENTATION NOTES:
- Cohen's f²: f² = R²/(1-R²)
- Semi-partial r²: For combined model, unique contribution of Learning_z
- AIC weights: Relative model probabilities
- Incremental validity: F-test for ΔR² (Model 7 vs Model 1)
"""
# =============================================================================

import sys
from pathlib import Path
import pandas as pd
import numpy as np
import statsmodels.api as sm
from scipy import stats

# Add project root to path for imports
PROJECT_ROOT = Path(__file__).resolve().parents[4]
sys.path.insert(0, str(PROJECT_ROOT))

# RQ directory
RQ_DIR = Path(__file__).resolve().parents[1]
LOG_FILE = RQ_DIR / "logs" / "step05_compute_effect_sizes.log"
OUTPUT_ES = RQ_DIR / "data" / "step05_effect_sizes.csv"
OUTPUT_IV = RQ_DIR / "data" / "step05_incremental_validity.csv"

# =============================================================================
# Configuration
# =============================================================================

BONFERRONI_ALPHA = 0.05 / 28 / 5
BOOTSTRAP_ITERATIONS = 1000
RANDOM_SEED = 42

# =============================================================================
# Logging Function
# =============================================================================

def log(msg):
    """Write to both log file and console."""
    with open(LOG_FILE, 'a', encoding='utf-8') as f:
        f.write(f"{msg}\n")
        f.flush()
    print(msg, flush=True)

# =============================================================================
# Effect Size Functions
# =============================================================================

def cohens_f2(r2):
    """Compute Cohen's f² from R²."""
    if r2 >= 1.0:
        return np.inf
    return r2 / (1.0 - r2)

def bootstrap_f2_ci(X, y, n_iterations=1000, random_state=42):
    """Compute bootstrap CI for Cohen's f²."""
    np.random.seed(random_state)
    n = len(y)
    f2_boot = []

    for i in range(n_iterations):
        idx = np.random.choice(n, size=n, replace=True)
        X_boot = X.iloc[idx] if isinstance(X, pd.DataFrame) else X[idx]
        y_boot = y.iloc[idx] if isinstance(y, pd.Series) else y[idx]

        try:
            model_boot = sm.OLS(y_boot, X_boot).fit()
            r2_boot = model_boot.rsquared
            f2_boot.append(cohens_f2(r2_boot))
        except:
            continue

    ci_lower = np.percentile(f2_boot, 2.5)
    ci_upper = np.percentile(f2_boot, 97.5)

    return ci_lower, ci_upper

# =============================================================================
# Main Analysis
# =============================================================================

if __name__ == "__main__":
    try:
        log("[START] Step 05: Compute Effect Sizes")

        # =========================================================================
        # STEP 1: Load Model Results
        # =========================================================================
        log("[LOAD] Loading model results...")

        models_path = RQ_DIR / "data" / "step04_model_results.csv"
        models_df = pd.read_csv(models_path)

        log(f"[LOADED] {models_path.name} ({len(models_df)} models)")

        # =========================================================================
        # STEP 2: Load Raw Data for Bootstrap
        # =========================================================================
        log("[LOAD] Loading raw data for bootstrap...")

        data_path = RQ_DIR / "data" / "step03_analysis_dataset.csv"
        df = pd.read_csv(data_path)

        log(f"[LOADED] {data_path.name} ({len(df)} participants)")

        # =========================================================================
        # STEP 3: Compute Effect Sizes
        # =========================================================================
        log("[COMPUTE] Computing Cohen's f² with bootstrap CIs...")

        effect_sizes = []

        # Model specifications (match step04)
        models_spec = [
            {'name': 'Model_1_Total', 'predictors': ['Total_z']},
            {'name': 'Model_2_Learning', 'predictors': ['Learning_z']},
            {'name': 'Model_3_LearningSlope', 'predictors': ['LearningSlope_z']},
            {'name': 'Model_4_Forgetting', 'predictors': ['Forgetting_z']},
            {'name': 'Model_5_Recognition', 'predictors': ['Recognition_z']},
            {'name': 'Model_6_PctRet', 'predictors': ['PctRet_z']},
            {'name': 'Model_7_Combined', 'predictors': ['Total_z', 'Learning_z']}
        ]

        for spec in models_spec:
            model_name = spec['name']
            predictors = spec['predictors']

            # Get R² from model results
            r2 = models_df[models_df['model'] == model_name]['R2'].values[0]

            # Compute Cohen's f²
            f2 = cohens_f2(r2)

            log(f"[{model_name}] R²={r2:.4f}, f²={f2:.4f}")

            # Bootstrap f² CI
            log(f"[BOOTSTRAP] {model_name} f² CI...")
            X = df[predictors]
            y = df['theta_all']
            X_with_const = sm.add_constant(X)

            f2_ci_lower, f2_ci_upper = bootstrap_f2_ci(X_with_const, y, n_iterations=BOOTSTRAP_ITERATIONS, random_state=RANDOM_SEED)

            log(f"[BOOTSTRAP] f² 95% CI: [{f2_ci_lower:.4f}, {f2_ci_upper:.4f}]")

            # Compute semi-partial r² (for combined model, unique contribution of Learning_z)
            if model_name == 'Model_7_Combined':
                # Fit reduced model (Total_z only)
                X_reduced = sm.add_constant(df[['Total_z']])
                model_reduced = sm.OLS(y, X_reduced).fit()
                r2_reduced = model_reduced.rsquared

                # Semi-partial r² = R²_full - R²_reduced
                sr2 = r2 - r2_reduced

                log(f"[SEMIPARTIAL] Learning_z unique contribution: sr²={sr2:.4f}")
            else:
                sr2 = np.nan

            effect_sizes.append({
                'model': model_name,
                'f2': f2,
                'f2_CI_lower': f2_ci_lower,
                'f2_CI_upper': f2_ci_upper,
                'sr2': sr2,
                'sr2_CI_lower': np.nan,  # Simplified - not bootstrapping sr²
                'sr2_CI_upper': np.nan
            })

        # =========================================================================
        # STEP 4: Compute AIC Weights
        # =========================================================================
        log("[COMPUTE] Computing AIC weights...")

        # Extract AIC values
        aic_values = models_df['AIC'].values

        # Compute AIC differences (relative to best model)
        min_aic = np.min(aic_values)
        delta_aic = aic_values - min_aic

        # Compute Akaike weights
        aic_weights = np.exp(-0.5 * delta_aic)
        aic_weights = aic_weights / np.sum(aic_weights)

        # Add to effect_sizes
        for i, es in enumerate(effect_sizes):
            es['AIC_weight'] = aic_weights[i]

        log("[COMPUTED] AIC weights (sum={:.4f})".format(np.sum(aic_weights)))

        # =========================================================================
        # STEP 5: Incremental Validity Test (Model 5 vs Model 1)
        # =========================================================================
        log("[INCREMENTAL] Testing incremental validity (Model 5 vs Model 1)...")

        # Get R² values
        r2_model1 = models_df[models_df['model'] == 'Model_1_Total']['R2'].values[0]
        r2_model5 = models_df[models_df['model'] == 'Model_7_Combined']['R2'].values[0]

        # Delta R²
        delta_r2 = r2_model5 - r2_model1

        # F-test for ΔR²
        n = len(df)
        k_reduced = 1  # Model 1 has 1 predictor
        k_full = 2     # Model 5 has 2 predictors
        df1 = k_full - k_reduced
        df2 = n - k_full - 1

        f_stat = (delta_r2 / df1) / ((1 - r2_model5) / df2)
        p_val = 1 - stats.f.cdf(f_stat, df1, df2)

        # Bonferroni correction
        p_bonf = p_val * (28 * 5)
        p_bonf = min(p_bonf, 1.0)

        log(f"[INCREMENTAL] ΔR²={delta_r2:.4f}, F({df1},{df2})={f_stat:.2f}, p={p_bonf:.6f}")

        incremental_validity = [{
            'delta_R2': delta_r2,
            'F_stat': f_stat,
            'df1': df1,
            'df2': df2,
            'p_uncorrected': p_val,
            'p_bonferroni': p_bonf,
            'delta_R2_CI': f"[{delta_r2:.4f}]"  # Simplified - point estimate
        }]

        # =========================================================================
        # STEP 6: Save Results
        # =========================================================================
        log("[SAVE] Saving effect sizes...")

        es_df = pd.DataFrame(effect_sizes)
        es_df.to_csv(OUTPUT_ES, index=False, encoding='utf-8')
        log(f"[SAVED] {OUTPUT_ES} ({len(es_df)} models)")

        log("[SAVE] Saving incremental validity test...")

        iv_df = pd.DataFrame(incremental_validity)
        iv_df.to_csv(OUTPUT_IV, index=False, encoding='utf-8')
        log(f"[SAVED] {OUTPUT_IV}")

        # =========================================================================
        # STEP 7: Summary
        # =========================================================================
        log("[SUMMARY] Effect sizes:")
        for _, row in es_df.iterrows():
            log(f"  {row['model']}: f²={row['f2']:.4f} [{row['f2_CI_lower']:.4f}, {row['f2_CI_upper']:.4f}], AIC_weight={row['AIC_weight']:.3f}")

        sig_mark = "***" if p_bonf < BONFERRONI_ALPHA else ""
        log(f"[SUMMARY] Incremental validity: ΔR²={delta_r2:.4f}, F({df1},{df2})={f_stat:.2f}, p={p_bonf:.6f}{sig_mark}")

        log("[SUCCESS] Step 05 complete")
        sys.exit(0)

    except Exception as e:
        log(f"[ERROR] {str(e)}")
        log("[TRACEBACK] Full error details:")
        import traceback
        with open(LOG_FILE, 'a', encoding='utf-8') as f:
            traceback.print_exc(file=f)
        traceback.print_exc()
        sys.exit(1)
